code = """import json
import re

# Load all papers mentioning physical activity
pa_file_path = locals()['var_functions.query_db:34']
with open(pa_file_path, 'r') as f:
    pa_papers = json.load(f)

# Load all citations
citations_path = locals()['var_functions.query_db:4']
with open(citations_path, 'r') as f:
    citations = json.load(f)

# Create citation map
citation_map = {}
for record in citations:
    citation_map[record['title']] = int(record['total_citations'])

# Function to extract year from paper text
def extract_year(text):
    # Check first 5000 characters for year information
    text_start = text[:5000]
    
    # Look for explicit 2016 mentions
    if '2016' in text_start:
        return 2016
    
    # Look for conference patterns (CHI '16, UbiComp '16, etc.)
    conferences = ['CHI', 'UbiComp', 'CSCW', 'DIS', 'PervasiveHealth', 'WWW', 'IUI', 'OzCHI', 'TEI', 'AH']
    for conf in conferences:
        pattern = conf + r"\s*['\"']?\s*16\b"
        if re.search(pattern, text_start, re.IGNORECASE):
            return 2016
    
    return None

# Find papers from 2016 in physical activity domain
papers_2016_physical_activity = []

for paper in pa_papers:
    year = extract_year(paper['text'])
    if year == 2016:
        title = paper['filename'].replace('.txt', '')
        total_citations = citation_map.get(title, 0)
        papers_2016_physical_activity.append({
            'title': title,
            'year': year,
            'total_citations': total_citations
        })

# Display results
print(f"Found {len(papers_2016_physical_activity)} papers from 2016 in physical activity domain:\n")
for paper in papers_2016_physical_activity:
    print(f"Title: {paper['title']}")
    print(f"Total Citations: {paper['total_citations']}")
    print()

# Return results as JSON
result = json.dumps(papers_2016_physical_activity, indent=2)
print('__RESULT__:')
print(result)"""

